 1	import type { FC } from 'react';
 2	
 3	import type { Concern } from '@kubev2v/types';
 4	import { Button, ButtonVariant, Label, Popover } from '@patternfly/react-core';
 5	import { isEmpty } from '@utils/helpers';
 6	import { useForkliftTranslation } from '@utils/i18n';
 7	
 8	import { getCategoryColor, getCategoryIcon, getCategoryTitle } from '../utils/category';
 9	
10	import ConcernList from './ConcernsList';
11	
12	const ConcernPopover: FC<{
13	  category: string;
14	  concerns: Concern[];
15	}> = ({ category, concerns }) => {
16	  const { t } = useForkliftTranslation();
17	
18	  if (isEmpty(concerns)) return null;
19	
20	  return (
21	    <Popover
22	      aria-label={`${category} popover`}
23	      headerContent={getCategoryTitle(category)}
24	      bodyContent={<ConcernList concerns={concerns} />}
25	      footerContent={t('Total: {{length}}', { length: concerns.length })}
26	    >
27	      <Button isInline variant={ButtonVariant.link}>
28	        <Label color={getCategoryColor(category)} icon={getCategoryIcon(category)}>
29	          {concerns.length}
30	        </Label>
31	      </Button>
32	    </Popover>
33	  );
34	};
35	
36	export default ConcernPopover;

